const input = $input.first().json;
const body = input.body || input;

const referralName = String(body.refferal_name || '').trim();
const referralPhone = String(body.referral_phone || '').trim();
const hasReferral = Boolean(referralName || referralPhone);
const baseObs = String(body.obs || '').trim();

const obsParts = [baseObs];
if (hasReferral) {
  obsParts.push(`Indicação: ${referralName || 'Não informado'} (${referralPhone || 'sem telefone'}).`);
}

return [{
  json: {
    nome: String(body.nome || '').trim(),
    email: String(body.email || '').trim(),
    tel: String(body.tel || '').replace(/\D/g, ''),
    obs: obsParts.filter(Boolean).join('\n'),
    canal_captacao: hasReferral ? 'Lead Magnet - Billing (Partner)' : 'Lead Magnet - Billing',
    indicador_nome: referralName,
    indicador_telefone: referralPhone,
    payload_original: body
  }
}];
